import { useState, useEffect, useCallback, useRef } from 'react';
import { barbershopsAPI } from '../lib/api';
import ShopCard from '../components/ShopCard';
import { useGeolocation } from '../hooks/useGeolocation';

export default function HomePage({ navigate }) {
  const [shops, setShops] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [locationText, setLocationText] = useState('');
  const [manualLocation, setManualLocation] = useState('');
  const [category, setCategory] = useState('todos');
  const [toast, setToast] = useState('');
  const [suggestions, setSuggestions] = useState([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [loadingSuggestions, setLoadingSuggestions] = useState(false);
  const [geoConsent, setGeoConsent] = useState('pending');
  const [radius, setRadius] = useState(10);
  const [locationCoords, setLocationCoords] = useState(null);
  const isMountedRef = useRef(true);
  const { location: deviceLocation, error: deviceLocationError, loading: deviceLocationLoading, refreshLocation: requestDeviceLocation } = useGeolocation();
  const hasLocation = Boolean(manualLocation || (geoConsent === 'granted' && deviceLocation));

  const showToast = (msg) => {
    setToast(msg);
    setTimeout(() => setToast(''), 2600);
  };

  const fetchAddressSuggestions = async (query) => {
    if (!query || query.length < 3) {
      setSuggestions([]);
      setShowSuggestions(false);
      return;
    }
    setLoadingSuggestions(true);
    try {
      const res = await fetch(`https://nominatim.openstreetmap.org/search?format=json&limit=5&q=${encodeURIComponent(query)}`);
      if (!res.ok) {
        setSuggestions([]);
        return;
      }
      const json = await res.json();
      setSuggestions(json || []);
      setShowSuggestions(true);
    } catch {
      setSuggestions([]);
    }
    setLoadingSuggestions(false);
  };

  const geocodeAddress = async (address) => {
    try {
      const res = await fetch(`https://nominatim.openstreetmap.org/search?format=json&limit=1&q=${encodeURIComponent(address)}`);
      if (!res.ok) return null;
      const json = await res.json();
      if (!json?.length) return null;
      return { lat: parseFloat(json[0].lat), lng: parseFloat(json[0].lon) };
    } catch {
      return null;
    }
  };

  const buildParams = (searchValue = search, manualLocationValue = manualLocation, coords = locationCoords, radiusValue = radius) => {
    const query = [searchValue, manualLocationValue].filter(Boolean).join(' ').trim();
    const params = {};
    if (query) params.search = query;
    if (coords) {
      params.lat = coords.lat;
      params.lng = coords.lng;
      params.radius = radiusValue;
    }
    return params;
  };

  const getDemoShops = (location = '') => {
    const baseShops = [
      { id: '1', name: 'Barber King', address: 'Rua das Flores, 123', city: 'Jaú', is_open: true, rating: 4.9, total_reviews: 124, distance_km: 0.3, services: [{ price: 30 }] },
      { id: '2', name: 'Studio 7', address: 'Av. Central, 456', city: 'Jaú', is_open: true, rating: 4.7, total_reviews: 89, distance_km: 0.8, services: [{ price: 25 }] },
      { id: '3', name: 'Noble Barbers', address: 'Rua Prudente de Moraes, 321', city: 'Jaú', is_open: true, rating: 4.8, total_reviews: 67, distance_km: 1.1, services: [{ price: 45 }] },
    ];

    if (location && location.toLowerCase().includes('são paulo')) {
      return [
        { id: '1', name: 'Barber King', address: 'Rua Consolação, 2000', city: 'São Paulo', is_open: true, rating: 4.9, total_reviews: 156, distance_km: 0.5, services: [{ price: 35 }] },
        { id: '2', name: 'Studio 7', address: 'Av. Paulista, 1500', city: 'São Paulo', is_open: true, rating: 4.8, total_reviews: 102, distance_km: 1.2, services: [{ price: 30 }] },
        { id: '3', name: 'Barber Club', address: 'Rua Oscar Freire, 456', city: 'São Paulo', is_open: true, rating: 4.7, total_reviews: 89, distance_km: 1.8, services: [{ price: 40 }] },
      ];
    }

    return baseShops;
  };

  const fetchShops = useCallback(async (searchValue = search, manualLocationValue = manualLocation, coords = locationCoords) => {
    setLoading(true);
    try {
      const params = buildParams(searchValue, manualLocationValue, coords);
      const { data } = await barbershopsAPI.getAll(params);
      if (isMountedRef.current) {
        setShops(data?.barbershops || []);
      }
    } catch {
      // Demo fallback com localização do usuário
      if (isMountedRef.current) {
        setShops(getDemoShops(manualLocationValue));
      }
    }
    if (isMountedRef.current) {
      setLoading(false);
    }
  }, [search, manualLocation, locationCoords, radius]);

  const handleApplyLocation = async () => {
    const value = locationText.trim();
    setManualLocation(value);
    setLoading(true);
    try {
      const coords = value ? await geocodeAddress(value) : (geoConsent === 'granted' ? deviceLocation : null);
      setLocationCoords(coords);
      const params = buildParams(search, value, coords);
      const { data } = await barbershopsAPI.getAll(params);
      if (isMountedRef.current) {
        setShops(data?.barbershops || []);
        showToast(value ? 'Local aplicado' : 'Endereço limpo');
      }
    } catch {
      // Demo fallback com localização do usuário
      if (isMountedRef.current) {
        setShops(getDemoShops(value));
      }
    }
    if (isMountedRef.current) {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (geoConsent === 'granted' && deviceLocation) {
      setLocationCoords(deviceLocation);
      fetchShops(search, manualLocation, deviceLocation);
    }
  }, [deviceLocation, geoConsent, search, manualLocation, fetchShops]);

  useEffect(() => {
    if (!locationCoords) return;

    const loadShops = async () => {
      setLoading(true);
      try {
        const params = buildParams(search, manualLocation, locationCoords, radius);
        const { data } = await barbershopsAPI.getAll(params);
        if (isMountedRef.current) {
          setShops(data?.barbershops || []);
        }
      } catch {
        if (isMountedRef.current) {
          setShops(getDemoShops(manualLocation));
        }
      }
      if (isMountedRef.current) {
        setLoading(false);
      }
    };

    loadShops();
  }, [radius, locationCoords, search, manualLocation]);

  useEffect(() => {
    return () => {
      isMountedRef.current = false;
    };
  }, []);

  useEffect(() => {
    if (deviceLocationError) {
      showToast(deviceLocationError);
    }
  }, [deviceLocationError]);

  const handleUseDeviceLocation = () => {
    setGeoConsent('granted');
    requestDeviceLocation();
  };

  const handleDenyDeviceLocation = () => {
    setGeoConsent('denied');
    showToast('Localização do dispositivo negada. Use o campo de endereço manual.');
  };

  const categories = [
    { id: 'todos', label: 'Todos', icon: '✂️' },
    { id: 'corte', label: 'Corte', icon: '💈' },
    { id: 'barba', label: 'Barba', icon: '🪒' },
    { id: 'pigmento', label: 'Pigmento', icon: '🎨' },
    { id: 'sobrancelha', label: 'Sobrancelha', icon: '👁️' },
  ];

  return (
    <div className="page" style={{ background: 'var(--dark)' }}>
      {toast && <div className="toast-msg">{toast}</div>}

      {/* Header */}
      <div style={{ padding: '5px 5px 0', display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', gap: 14 }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 50, flex: 1, minWidth: 0 }}>
          <div className="logo-text">LE<span>BUX</span></div>
          <div style={{ flex: 1, minWidth: 0 }}>
            <div style={{ fontSize: 13, color: 'var(--muted)', textTransform: 'uppercase', letterSpacing: 1, marginBottom: 8 }}>Sua localização</div>
            <div style={{ fontSize: 16, fontWeight: 18, color: 'var(--text)', lineHeight: 1.4, minHeight: 24 }}>
              {manualLocation ? manualLocation : (geoConsent === 'granted' ? 'Localização do dispositivo em uso' : 'Digite seu endereço abaixo')}
            </div>
          </div>
        </div>
        <button className="back-btn" onClick={() => navigate('login')} title="Perfil">👤</button>
      </div>

      {(geoConsent === 'pending' || geoConsent === 'denied') && (
        <div style={{ margin: '16px 20px 0', padding: 18, borderRadius: 16, background: 'var(--dark2)', border: '1px solid var(--border)' }}>
          <div style={{ fontWeight: 700, fontSize: 15, marginBottom: 10 }}>Autorização de uso da localização</div>
          <div style={{ color: 'var(--muted)', fontSize: 14, lineHeight: 1.6, marginBottom: 16 }}>
            Para apresentar barbearias próximas com maior precisão, o Lebux solicita acesso à localização do seu dispositivo. Essa permissão será usada apenas para buscar serviços e exibir resultados mais relevantes na sua região.
          </div>
          <div style={{ color: 'var(--muted)', fontSize: 13, marginBottom: 16 }}>
            Você pode negar o acesso e inserir manualmente sua cidade, bairro ou endereço.
          </div>
          <div style={{ display: 'flex', flexWrap: 'wrap', gap: 10 }}>
            <button className="btn-primary" style={{ minWidth: 160 }} onClick={handleUseDeviceLocation}>
              Permitir localização
            </button>
            <button className="btn-secondary" style={{ minWidth: 160, background: 'var(--dark3)', color: 'var(--text)' }} onClick={handleDenyDeviceLocation}>
              Negar acesso
            </button>
          </div>
          {geoConsent === 'denied' && (
            <div style={{ marginTop: 12, color: 'var(--muted)', fontSize: 13 }}>
              Você pode digitar sua cidade, bairro ou endereço abaixo.
            </div>
          )}
        </div>
      )}

      {hasLocation && locationCoords && (
        <div style={{ margin: '16px 20px 0', padding: 18, borderRadius: 16, background: 'var(--dark2)', border: '1px solid var(--border)' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', gap: 16, flexWrap: 'wrap' }}>
            <div style={{ minWidth: 0, flex: 1 }}>
              <div style={{ fontSize: 13, color: 'var(--muted)', textTransform: 'uppercase', letterSpacing: 1, marginBottom: 6 }}>Local selecionado</div>
              <div style={{ fontSize: 16, fontWeight: 700, color: 'var(--text)', lineHeight: 1.4, minHeight: 24 }}>
                {manualLocation || 'Localização do dispositivo em uso'}
              </div>
            </div>
            <div style={{ minWidth: 180, display: 'flex', flexDirection: 'column', gap: 8 }}>
              <label htmlFor="radius-select" style={{ fontSize: 13, color: 'var(--muted)', textTransform: 'uppercase', letterSpacing: 1 }}>Raio de busca</label>
              <select
                id="radius-select"
                value={radius}
                onChange={(e) => setRadius(Number(e.target.value))}
                style={{ minWidth: 180, padding: '12px 14px', fontSize: 15, borderRadius: 12, border: '1px solid var(--border)', background: 'var(--dark3)', color: 'var(--text)' }}
              >
                {[5, 10, 20].map(option => (
                  <option key={option} value={option}>{option} km</option>
                ))}
              </select>
            </div>
          </div>
          <div style={{ marginTop: 14, color: 'var(--muted)', fontSize: 13 }}>
            Exibindo estabelecimentos próximos ao local selecionado, com base nas coordenadas definidas.
          </div>
        </div>
      )}

      {!hasLocation && (
        <div style={{ margin: '16px 20px 0', position: 'relative' }}>
          <input
            className="input-field"
            placeholder="Digite sua cidade, bairro ou endereço"
            value={locationText}
            onChange={(e) => {
              setLocationText(e.target.value);
              fetchAddressSuggestions(e.target.value);
            }}
            onKeyDown={e => e.key === 'Enter' && handleApplyLocation()}
            onBlur={() => setTimeout(() => setShowSuggestions(false), 200)}
            style={{ width: '100%', padding: '20px 18px', fontSize: 18, minHeight: 68 }}
          />
          {showSuggestions && suggestions.length > 0 && (
            <div style={{
              position: 'absolute',
              top: '100%',
              left: 0,
              right: 0,
              background: 'var(--dark2)',
              border: '1px solid var(--border)',
              borderTop: 'none',
              borderRadius: '0 0 12px 12px',
              maxHeight: 280,
              overflowY: 'auto',
              zIndex: 1000,
              marginTop: -1
            }}>
              {suggestions.map((suggestion, idx) => (
                <button
                  key={idx}
                  onClick={async () => {
                    setLocationText(suggestion.display_name);
                    setManualLocation(suggestion.display_name);
                    setShowSuggestions(false);
                    setLoading(true);
                    try {
                      const coords = await geocodeAddress(suggestion.display_name);
                      setLocationCoords(coords);
                      const params = buildParams(search, suggestion.display_name, coords);
                      const { data } = await barbershopsAPI.getAll(params);
                      if (isMountedRef.current) {
                        setShops(data?.barbershops || []);
                        showToast('Local aplicado');
                      }
                    } catch {
                      // Demo fallback com localização do usuário
                      if (isMountedRef.current) {
                        setShops(getDemoShops(suggestion.display_name));
                      }
                    }
                    if (isMountedRef.current) {
                      setLoading(false);
                    }
                  }}
                  style={{
                    display: 'block',
                    width: '100%',
                    padding: '14px 16px',
                    background: 'transparent',
                    border: 'none',
                    color: 'var(--text)',
                    textAlign: 'left',
                    cursor: 'pointer',
                    fontSize: 14,
                    borderBottom: '1px solid var(--border)',
                    transition: 'background 0.15s'
                  }}
                  onMouseEnter={(e) => e.currentTarget.style.background = 'var(--dark3)'}
                  onMouseLeave={(e) => e.currentTarget.style.background = 'transparent'}
                >
                  {suggestion.display_name}
                </button>
              ))}
            </div>
          )}
          <button
            className="btn-primary"
            style={{ width: '100%', marginTop: 12, padding: '16px 18px', fontSize: 16, minHeight: 52 }}
            onClick={handleApplyLocation}
          >
            Aplicar
          </button>
        </div>
      )}

      {/* Search */}
      <div style={{ margin: '12px 20px 0', display: 'flex', gap: 10, alignItems: 'center', flexWrap: 'wrap' }}>
        <div style={{ position: 'relative', flex: '1 1 240px', minWidth: 0 }}>
          <span style={{ position: 'absolute', left: 14, top: '50%', transform: 'translateY(-50%)', opacity: 0.4, fontSize: 16 }}>🔍</span>
          <input
            className="input-field"
            style={{ paddingLeft: 40, paddingRight: 16, minHeight: 52, fontSize: 16 }}
            placeholder="Buscar barbearias, serviços ou endereço..."
            value={search}
            onChange={e => setSearch(e.target.value)}
            onKeyDown={e => e.key === 'Enter' && fetchShops()}
          />
        </div>
        <button
          className="btn-primary"
          style={{ flexShrink: 0, minWidth: 120, padding: '14px 18px', fontSize: 16, minHeight: 52 }}
          onClick={fetchShops}
        >
          Buscar
        </button>
      </div>

      {/* Promo banner */}
      <div style={{ margin: '16px 20px 0', background: 'linear-gradient(135deg, var(--gold), #6BA8F7)', borderRadius: 14, padding: '14px 18px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <div>
          <div style={{ fontWeight: 700, color: '#0F0F0F', fontSize: 15 }}>Primeira barba grátis!</div>
          <div style={{ fontSize: 12, color: 'rgba(0,0,0,0.6)' }}>Para novos clientes cadastrados</div>
        </div>
        <div style={{ background: 'rgba(0,0,0,0.2)', borderRadius: 8, padding: '6px 12px', fontFamily: 'Bebas Neue, sans-serif', fontSize: 15, letterSpacing: 2, color: '#0F0F0F', fontWeight: 700 }}>LEBUX1</div>
      </div>

      {/* Categories */}
      <div style={{ margin: '20px 0 0' }}>
        <div style={{ padding: '0 20px', marginBottom: 12 }} className="section-title">Serviços</div>
        <div style={{ display: 'flex', gap: 10, padding: '0 20px', overflowX: 'auto', scrollbarWidth: 'none' }}>
          {categories.map(c => (
            <button key={c.id} onClick={() => setCategory(c.id)}
              style={{
                flexShrink: 0, background: category === c.id ? 'var(--gold)' : 'var(--dark3)',
                border: `1px solid ${category === c.id ? 'var(--gold)' : 'var(--border)'}`,
                borderRadius: 10, padding: '10px 16px', cursor: 'pointer',
                display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 6, minWidth: 68
              }}>
              <span style={{ fontSize: 18 }}>{c.icon}</span>
              <span style={{ fontSize: 11, fontWeight: 500, color: category === c.id ? 'var(--dark)' : 'var(--muted)', whiteSpace: 'nowrap' }}>{c.label}</span>
            </button>
          ))}
        </div>
      </div>

      {/* Shops List */}
      <div style={{ margin: '20px 0 0' }}>
        <div style={{ padding: '0 20px', marginBottom: 14, display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: 8 }}>
          <div>
            <div className="section-title">{manualLocation ? 'Próximas do local selecionado' : 'Próximas de você'}</div>
            {manualLocation && (
              <div style={{ fontSize: 13, color: 'var(--muted)', marginTop: 4 }}>Baseado na localização escolhida: {manualLocation}</div>
            )}
          </div>
          <span style={{ fontSize: 13, color: 'var(--muted)' }}>{shops.length} encontradas</span>
        </div>

        {loading ? (
          <div className="loading"><div className="spinner" /><span>Buscando barbearias...</span></div>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 12, padding: '0 20px' }}>
            {shops.map(shop => (
              <ShopCard key={shop.id} shop={shop} onClick={() => navigate('barbershop', { shop })} />
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
